class Solution:
    def robotWithString(self, s: str) -> str:
        t, stack, ans = [], [], []
        min_future_char = 'z'
        for char in s:
            while stack and stack[-1] <= min_future_char:
                ans.append(stack.pop())
            stack.append(char)
            min_future_char = min(min_future_char, char)
        while stack:
            ans.append(stack.pop())
        return ''.join(ans)
